command:
cat << 'EOF' > patch.cjs
const fs = require('fs');
const file = 'src/utils/persistence.ts';
let content = fs.readFileSync(file, 'utf8');
content = content.replace('":(glob,exclude)session_*.log",', '":(glob,exclude)session_*.log",
				":(glob,exclude)npm-debug.log*",
				":(glob,exclude)yarn-debug.log*",
				":(glob,exclude)yarn-error.log*",');
const oldIgnore = '	private isIgnoredPath(path: string): boolean {
		return path.startsWith(".backstop/") || /^session_.*\.log$/.test(path);
	}';
const newIgnore = '	private isIgnoredPath(path: string): boolean {
		if (path.startsWith(".backstop/") || /^session_.*\.log$/.test(path)) {
			return true;
		}
		const filename = path.split("/").pop() || path;
		return (
			filename.startsWith("npm-debug.log") ||
			filename.startsWith("yarn-debug.log") ||
			filename.startsWith("yarn-error.log")
		);
	}';
content = content.replace(oldIgnore, newIgnore);
fs.writeFileSync(file, content);
EOF
node patch.cjs
rm patch.cjs

